module RefModule(  
    input clk,  
    input reset,  
    output reg out  
);  
    reg [2:0] unused_count;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            unused_count <= 3'b000;  
            out <= 1'b0;  
        end else begin  
            unused_count <= unused_count + 1;  
            if (unused_count == 3'b100) // When unused_count reaches 4  
                out <= 1'b1;  
            else  
                out <= 1'b0;  
        end  
    end  
endmodule
